// Custom policy: require Environment tag with approved values
{
  "properties": {
    "displayName": "Require Environment tag with approved values",
    "mode": "Indexed",
    "parameters": {
      "effect": {
        "type": "String",
        "defaultValue": "Deny",
        "allowedValues": ["Deny", "Audit", "Disabled"],
        "metadata": { "displayName": "Effect" }
      },
      "allowedEnvironments": {
        "type": "Array",
        "defaultValue": ["prod", "staging", "dev", "test", "sandbox"],
        "metadata": { "displayName": "Approved Environment tag values" }
      }
    },
    "policyRule": {
      "if": {
        "not": {
          "field": "tags[Environment]",
          "in": "[parameters('allowedEnvironments')]"
        }
      },
      "then": {
        "effect": "[parameters('effect')]"
      }
    }
  }
}

# Exclude specific subscriptions from the Deny tag policy
# (e.g., platform subscription, managed MG for Azure-internal resources)
az policy assignment create \
  --name require-costcenter-tag \
  --policy '871b6d14-10aa-478d-b590-94f262ecfa99' \
  --management-group mg-corp \
  --params '{"tagName": {"value": "CostCenter"}}' \
  --not-scopes \
    /subscriptions/$PLATFORM_SUB_ID \
    /subscriptions/$SANDBOX_SUB_ID

# Exclude resource types that don't support tags
# Note: mode=Indexed automatically skips resources that don't support tags
# If your policy uses mode=All, add type exclusions to the if condition:
{
  "if": {
    "allOf": [
      {
        "field": "type",
        "notIn": [
          "Microsoft.Network/networkInterfaces",
          "Microsoft.Compute/virtualMachines/extensions",
          "Microsoft.Resources/deployments"
        ]
      },
      {
        "not": {
          "field": "tags[CostCenter]",
          "exists": "true"
        }
      }
    ]
  }
}

# Check which resource types do NOT support tags (mode Indexed excludes these)
az policy alias list \
  --query "[?contains(name, 'tags') && defaultMetadata.attributes=='Modifiable'].name" -o tsv \
  | sort | head -20

# Terraform: assign built-in Deny policy and Modify policy for CostCenter tag

variable "corp_mg_id" { type = string }
variable "location"   { type = string  default = "eastus2" }

# 1. Require CostCenter tag — Deny effect
resource "azurerm_management_group_policy_assignment" "require_costcenter" {
  name                 = "require-costcenter"
  management_group_id  = var.corp_mg_id
  policy_definition_id = "/providers/Microsoft.Authorization/policyDefinitions/871b6d14-10aa-478d-b590-94f262ecfa99"
  display_name         = "Require CostCenter tag on all resources"

  parameters = jsonencode({
    tagName = { value = "CostCenter" }
  })
}

# 2. Inherit CostCenter from resource group — Modify effect
resource "azurerm_management_group_policy_assignment" "inherit_costcenter" {
  name                 = "inherit-costcenter-rg"
  management_group_id  = var.corp_mg_id
  policy_definition_id = "/providers/Microsoft.Authorization/policyDefinitions/cd3aa116-8754-49c9-a813-ad46512ece54"
  display_name         = "Inherit CostCenter from resource group"
  location             = var.location

  identity { type = "SystemAssigned" }

  parameters = jsonencode({
    tagName = { value = "CostCenter" }
  })
}

# 3. Grant Contributor to the Modify MI
resource "azurerm_role_assignment" "inherit_costcenter_mi" {
  scope                = var.corp_mg_id
  role_definition_name = "Contributor"
  principal_id         = azurerm_management_group_policy_assignment.inherit_costcenter.identity[0].principal_id
}

# 4. Remediation task to tag existing resources
resource "azurerm_management_group_policy_remediation" "inherit_costcenter" {
  name                    = "remediate-costcenter-inherit"
  management_group_id     = var.corp_mg_id
  policy_assignment_id    = azurerm_management_group_policy_assignment.inherit_costcenter.id
  resource_discovery_mode = "ExistingNonCompliant"

  depends_on = [azurerm_role_assignment.inherit_costcenter_mi]
}

{
  "mode": "All",
  "parameters": {
    "tagName": {
      "type": "String",
      "metadata": { "displayName": "Tag Name", "description": "Name of the tag to enforce allowed values for" }
    },
    "allowedValues": {
      "type": "Array",
      "metadata": { "displayName": "Allowed Values", "description": "List of allowed tag values" }
    }
  },
  "policyRule": {
    "if": {
      "allOf": [
        {
          "field": "[concat('tags[', parameters('tagName'), ']')]",
          "exists": "true"
        },
        {
          "field": "[concat('tags[', parameters('tagName'), ']')]",
          "notIn": "[parameters('allowedValues')]"
        }
      ]
    },
    "then": {
      "effect": "Deny"
    }
  }
}

{
  "mode": "Indexed",
  "parameters": {
    "tagName": {
      "type": "String",
      "metadata": { "displayName": "Tag Name to propagate from RG to resource" }
    }
  },
  "policyRule": {
    "if": {
      "field": "[concat('tags[', parameters('tagName'), ']')]",
      "notEquals": "[resourceGroup().tags[parameters('tagName')]]"
    },
    "then": {
      "effect": "Modify",
      "details": {
        "roleDefinitionIds": [
          "/providers/microsoft.authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
        ],
        "operations": [
          {
            "operation": "addOrReplace",
            "field": "[concat('tags[', parameters('tagName'), ']')]",
            "value": "[resourceGroup().tags[parameters('tagName')]]"
          }
        ]
      }
    }
  }
}

# Create a policy set definition (initiative) that bundles all required tag policies
# Built-in policy IDs:
# 96670d01: Require tag and its value on resources  (for specific tag+value)
# 871b6d14: Require a tag on resources              (tag presence only)
# cd3aa116: Inherit a tag from the resource group   (Modify/propagate)

cat > /tmp/tag-initiative-params.json << 'EOF'
{
  "costCenterTag": {
    "type": "String",
    "metadata": { "displayName": "CostCenter Tag Name" },
    "defaultValue": "CostCenter"
  },
  "environmentTag": {
    "type": "String",
    "metadata": { "displayName": "Environment Tag Name" },
    "defaultValue": "Environment"
  },
  "ownerTag": {
    "type": "String",
    "metadata": { "displayName": "Owner Tag Name" },
    "defaultValue": "Owner"
  },
  "applicationTag": {
    "type": "String",
    "metadata": { "displayName": "Application Tag Name" },
    "defaultValue": "Application"
  }
}
EOF

cat > /tmp/tag-initiative-definitions.json << 'EOF'
[
  {
    "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/871b6d14-10aa-478d-b590-94f262ecfa99",
    "policyDefinitionReferenceId": "require-costtag",
    "parameters": { "tagName": { "value": "[parameters('costCenterTag')]" } }
  },
  {
    "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/871b6d14-10aa-478d-b590-94f262ecfa99",
    "policyDefinitionReferenceId": "require-envtag",
    "parameters": { "tagName": { "value": "[parameters('environmentTag')]" } }
  },
  {
    "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/871b6d14-10aa-478d-b590-94f262ecfa99",
    "policyDefinitionReferenceId": "require-ownertag",
    "parameters": { "tagName": { "value": "[parameters('ownerTag')]" } }
  },
  {
    "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/871b6d14-10aa-478d-b590-94f262ecfa99",
    "policyDefinitionReferenceId": "require-apptag",
    "parameters": { "tagName": { "value": "[parameters('applicationTag')]" } }
  },
  {
    "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/cd3aa116-8754-49c9-a813-ad46512ece54",
    "policyDefinitionReferenceId": "propagate-costtag",
    "parameters": { "tagName": { "value": "[parameters('costCenterTag')]" } }
  },
  {
    "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/cd3aa116-8754-49c9-a813-ad46512ece54",
    "policyDefinitionReferenceId": "propagate-envtag",
    "parameters": { "tagName": { "value": "[parameters('environmentTag')]" } }
  },
  {
    "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/cd3aa116-8754-49c9-a813-ad46512ece54",
    "policyDefinitionReferenceId": "propagate-ownertag",
    "parameters": { "tagName": { "value": "[parameters('ownerTag')]" } }
  },
  {
    "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/cd3aa116-8754-49c9-a813-ad46512ece54",
    "policyDefinitionReferenceId": "propagate-apptag",
    "parameters": { "tagName": { "value": "[parameters('applicationTag')]" } }
  }
]
EOF

az policy set-definition create   --name "required-tags-initiative"   --display-name "Required tag enforcement and propagation"   --description "Requires CostCenter, Environment, Owner, and Application tags on all resources and propagates from resource group when absent"   --management-group mg-corp   --definitions @/tmp/tag-initiative-definitions.json   --params @/tmp/tag-initiative-params.json

# Assign the initiative
az policy assignment create   --name "required-tags"   --display-name "Required tag enforcement — corp"   --policy-set-definition "required-tags-initiative"   --scope "/providers/Microsoft.Management/managementGroups/mg-corp"   --mi-system-assigned   --location eastus

// tag-governance.bicep
// Deploy at management group scope:
// az deployment mg create --management-group-id mg-corp --location eastus --template-file tag-governance.bicep

targetScope = 'managementGroup'

param managementGroupId string = 'mg-corp'
param location string = 'eastus'
param requiredTags array = [
  'CostCenter'
  'Environment'
  'Owner'
  'Application'
]

// Policy definitions: one Deny (require tag) per required tag
resource requireTagDefinitions 'Microsoft.Authorization/policyDefinitions@2021-06-01' = [for tag in requiredTags: {
  name: 'require-tag-${toLower(tag)}'
  properties: {
    displayName: 'Require ${tag} tag on resources'
    mode: 'Indexed'
    policyType: 'Custom'
    parameters: {}
    policyRule: {
      if: {
        field: 'tags[${tag}]'
        exists: 'false'
      }
      then: {
        effect: 'Deny'
      }
    }
  }
}]

// Policy definitions: one Modify (propagate from RG) per required tag
resource propagateTagDefinitions 'Microsoft.Authorization/policyDefinitions@2021-06-01' = [for tag in requiredTags: {
  name: 'propagate-tag-${toLower(tag)}'
  properties: {
    displayName: 'Propagate ${tag} from resource group'
    mode: 'Indexed'
    policyType: 'Custom'
    parameters: {}
    policyRule: {
      if: {
        field: 'tags[${tag}]'
        notEquals: '[resourceGroup().tags['${tag}']]'
      }
      then: {
        effect: 'Modify'
        details: {
          roleDefinitionIds: [
            '/providers/microsoft.authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c'
          ]
          operations: [
            {
              operation: 'addOrReplace'
              field: 'tags[${tag}]'
              value: '[resourceGroup().tags['${tag}']]'
            }
          ]
        }
      }
    }
  }
}]

// Assignment for Deny policies
resource denyAssignments 'Microsoft.Authorization/policyAssignments@2022-06-01' = [for (tag, i) in requiredTags: {
  name: 'deny-missing-${toLower(tag)}'
  location: location
  properties: {
    displayName: 'Deny resources without ${tag} tag'
    policyDefinitionId: requireTagDefinitions[i].id
    enforcementMode: 'Default'
  }
  dependsOn: [requireTagDefinitions]
}]

// Assignment for Modify policies (requires managed identity)
resource modifyAssignments 'Microsoft.Authorization/policyAssignments@2022-06-01' = [for (tag, i) in requiredTags: {
  name: 'modify-propagate-${toLower(tag)}'
  location: location
  identity: {
    type: 'SystemAssigned'
  }
  properties: {
    displayName: 'Propagate ${tag} tag from resource group'
    policyDefinitionId: propagateTagDefinitions[i].id
    enforcementMode: 'Default'
  }
  dependsOn: [propagateTagDefinitions]
}]

// Role assignments: Contributor for each Modify managed identity
resource roleAssignments 'Microsoft.Authorization/roleAssignments@2022-04-01' = [for (tag, i) in requiredTags: {
  name: guid(modifyAssignments[i].name, 'Contributor')
  properties: {
    roleDefinitionId: '/providers/microsoft.authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c'
    principalId: modifyAssignments[i].identity.principalId
    principalType: 'ServicePrincipal'
  }
  dependsOn: [modifyAssignments]
}]
